### 2. Criando o Comando `;setup-register`
Este comando vai:
1. Sincronizar todos os usuários sem cargo para o cargo de Não-Registrado.
2. Limpar o canal de registro.
3. Enviar a Interface de Registro (Embed + Botões).

[FWP_ACTION]{"type":"cs_write_file","path":"commands/setup_server.ts","content":"import { 
  ActionRowBuilder, 
  ButtonBuilder, 
  ButtonStyle, 
  EmbedBuilder, 
  Message, 
  PermissionFlagsBits, 
  TextChannel 
} from 'discord.js';
import type { PrefixCommand } from '../../ai/commandRegistry.js';

export const prefixCommand: PrefixCommand = {
  trigger: 'setup-register',
  description: 'Inicializa o portal de registro interativo.',
  async execute(message: Message) {
    const OWNER_ID = '892469618063589387';
    const REG_CHANNEL_ID = '1495985460281999522';
    const UNREG_ROLE_ID = '1495985456943202327';
    const MEMBER_ROLE_ID = '1493095650555068576';

    if (message.author.id !== OWNER_ID) return message.reply('❌ Acesso restrito ao Dono.');
    if (message.channel.id !== REG_CHANNEL_ID) return message.reply(`❌ Execute este comando em <#${REG_CHANNEL_ID}>.`);

    const channel = message.channel as TextChannel;
    await channel.bulkDelete(100).catch(() => {});

    // Sincronização de Massa
    const members = await message.guild!.members.fetch();
    let synced = 0;
    for (const [id, member] of members) {
      if (!member.user.bot && !member.roles.cache.has(MEMBER_ROLE_ID) && !member.roles.cache.has(UNREG_ROLE_ID)) {
        await member.roles.add(UNREG_ROLE_ID).catch(() => {});
        synced++;
      }
    }

    // Interface de Registro
    const embed = new EmbedBuilder()
      .setTitle('🔰 PORTAL DE ACESSO - FAW')
      .setColor('#2b2d31')
      .setDescription(
        'Bem-vindo ao laboratório de engenharia reversa e desenvolvimento **FAW**.\n\n' +
        'Para obter acesso aos demais setores, você precisa se registrar em nossa database.\n\n' +
        '**Instruções:**\n' +
        '1️⃣ Clique no botão abaixo para iniciar.\n' +
        '2️⃣ Defina seu Nickname operacional.\n' +
        '3️⃣ Escolha se deseja a Tag de Lealdade `[FAW]` (Cor Roxa).\n\n' +
        '⚠️ *Ao prosseguir, você concorda com as diretrizes de segurança do servidor.*'
      )
      .setImage('https://i.imgur.com/uR1jWqR.png') // Banner opcional
      .setFooter({ text: 'FAW Security Protocol v4.2' });

    const row = new ActionRowBuilder<ButtonBuilder>().addComponents(
      new ButtonBuilder()
        .setCustomId('faw_start_reg')
        .setLabel('Iniciar Registro')
        .setStyle(ButtonStyle.Primary)
        .setEmoji('🛡️')
    );

    await channel.send({ embeds: [embed], components: [row] });
    await message.reply(`✅ Setup concluído. **${synced}** usuários sincronizados como Não-Registrados.`);
  }
};"}[/FWP_ACTION]

### 3. O Cérebro do Registro (Modals e Processamento)
Vou criar um handler específico para as interações de registro. Ele vai lidar com a abertura da caixa de texto (Modal) e a troca de cargos.

[FWP_ACTION]{"type":"cs_write_file","path":"../../src/events/interactionCreate.ts","content":"import { 
  Events, 
  Interaction, 
  ModalBuilder, 
  TextInputBuilder, 
  TextInputStyle, 
  ActionRowBuilder, 
  ModalSubmitInteraction 
} from 'discord.js';

export default {
  name: Events.InteractionCreate,
  async execute(interaction: Interaction) {
    const UNREG_ROLE_ID = '1495985456943202327';
    const MEMBER_ROLE_ID = '1493095650555068576';
    const TAG_ROLE_ID = '1495985457895309333';

    // 1. Botão Iniciar
    if (interaction.isButton() && interaction.customId === 'faw_start_reg') {
      const modal = new ModalBuilder()
        .setCustomId('faw_reg_modal')
        .setTitle('Registro Operacional FAW');

      const nickInput = new TextInputBuilder()
        .setCustomId('reg_nick')
        .setLabel('QUAL SEU NICKNAME?')
        .setStyle(TextInputStyle.Short)
        .setMinLength(2)
        .setMaxLength(20)
        .setRequired(true);

      const tagInput = new TextInputBuilder()
        .setCustomId('reg_tag_opt')
        .setLabel('DESEJA A TAG [FAW] E COR ROXA? (SIM/NAO)')
        .setStyle(TextInputStyle.Short)
        .setMaxLength(3)
        .setRequired(true);

      modal.addComponents(
        new ActionRowBuilder<TextInputBuilder>().addComponents(nickInput),
        new ActionRowBuilder<TextInputBuilder>().addComponents(tagInput)
      );

      await interaction.showModal(modal);
    }

    // 2. Processar Modal
    if (interaction.isModalSubmit() && interaction.customId === 'faw_reg_modal') {
      const nick = interaction.fields.getTextInputValue('reg_nick');
      const wantTag = interaction.fields.getTextInputValue('reg_tag_opt').toLowerCase() === 'sim';
      const member = interaction.member! as any;

      try {
        let finalNick = nick;
        if (wantTag) {
          finalNick = `FAW | ${nick}`;
          await member.roles.add(TAG_ROLE_ID).catch(() => {});
        }

        await member.setNickname(finalNick).catch(() => {});
        await member.roles.add(MEMBER_ROLE_ID);
        await member.roles.remove(UNREG_ROLE_ID).catch(() => {});

        await interaction.reply({ 
          content: `✅ Registro concluído, **${finalNick}**! O servidor foi liberado para você.`, 
          ephemeral: true 
        });
      } catch (err) {
        await interaction.reply({ content: '❌ Erro ao processar registro. Verifique se meu cargo está no topo.', ephemeral: true });
      }
    }
  }
};"}[/FWP_ACTION]

